        "html": "<!DOCTYPE html>\n<html lang=\"ko\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n  <title>컴퓨터 수업 - 1페이지</title>\n  <style>\n    *{box-sizing:border-box}\n    html,body{height:100%}\n    body{\n      margin:0;\n      font-family:Arial,Helvetica,sans-serif;\n      background:#0f172a;\n      color:#fff;\n      overflow:hidden;\n    }\n    .slide{\n      width:100vw;\n      height:100svh;\n      min-height:100vh;\n      position:relative;\n      background-image:url('https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=1800&q=80');\n      background-size:cover;\n      background-position:center;\n      background-repeat:no-repeat;\n      overflow:hidden;\n      padding:26px 34px;\n      display:flex;\n      align-items:center;\n      justify-content:center;\n    }\n    .overlay{\n      position:absolute;\n      inset:0;\n      background:linear-gradient(180deg,rgba(15,23,42,.42),rgba(15,23,42,.84));\n    }\n    .frame{\n      position:relative;\n      z-index:2;\n      width:min(1040px,100%);\n      text-align:center;\n      background:rgba(15,23,42,.52);\n      border:1px solid rgba(255,255,255,.14);\n      border-radius:28px;\n      backdrop-filter:blur(12px);\n      box-shadow:0 24px 60px rgba(0,0,0,.28);\n      padding:28px 26px 30px;\n    }\n    .hero-icon{\n      font-size:64px;\n      line-height:1;\n      margin-bottom:10px;\n    }\n    .title{\n      margin:0;\n      font-size:clamp(34px,4.8vw,58px);\n      font-weight:800;\n      line-height:1.1;\n    }\n    .subtitle-wrap{margin-top:10px; margin-bottom:6px;}\n    .subtitle{\n      font-size:clamp(18px,1.9vw,24px);\n      line-height:1.4;\n      margin:0;\n    }\n    .subtitle-small{\n      font-size:13px;\n      line-height:1.35;\n      opacity:.88;\n      margin-top:4px;\n    }\n    .grid{\n      display:grid;\n      grid-template-columns:repeat(2,minmax(0,1fr));\n      gap:16px;\n      width:min(900px,100%);\n      margin:18px auto 0;\n    }\n    .card{\n      background:rgba(255,255,255,.08);\n      border:1px solid rgba(255,255,255,.14);\n      border-radius:22px;\n      overflow:hidden;\n      text-align:left;\n      min-width:0;\n    }\n    .card img{\n      width:100%;\n      height:180px;\n      object-fit:cover;\n      display:block;\n    }\n    .card-body{\n      padding:14px 16px 16px;\n    }\n    .card-title{\n      margin:0 0 6px;\n      font-size:22px;\n      font-weight:800;\n      line-height:1.2;\n    }\n    .card-text{\n      margin:0;\n      font-size:15px;\n      line-height:1.4;\n      opacity:.96;\n    }\n    .card-trans{\n      margin-top:8px;\n      font-size:11px;\n      line-height:1.3;\n      opacity:.8;\n    }\n    @media (max-width:900px){\n      .slide{padding:20px 20px;}\n      .frame{padding:22px 18px 24px;}\n      .grid{gap:12px; margin-top:18px;}\n      .card img{height:150px;}\n      .card-title{font-size:19px;}\n      .card-text{font-size:14px;}\n    }\n    @media (max-width:640px){\n      .slide{padding:14px 12px;}\n      .frame{padding:18px 14px 20px; border-radius:20px;}\n      .hero-icon{font-size:48px;}\n      .title{font-size:28px;}\n      .subtitle{font-size:15px;}\n      .subtitle-small{font-size:11px;}\n      .grid{grid-template-columns:1fr; gap:10px; margin-top:16px;}\n      .card img{height:120px;}\n      .card-body{padding:12px 12px 14px;}\n      .card-title{font-size:17px;}\n      .card-text{font-size:13px;}\n      .card-trans{font-size:10px;}\n    }\n  </style>\n<style data-slide-frame-preset>\n  html,\n  body {\n    width: 100% !important;\n    height: 100% !important;\n    overflow: hidden !important;\n  }\n\n  body {\n    margin: 0 !important;\n    overscroll-behavior: none !important;\n  }\n\n  *,\n  *::before,\n  *::after {\n    box-sizing: border-box !important;\n  }\n</style>\n</head>\n<body>\n  <section class=\"slide\">\n    <div class=\"overlay\"></div>\n\n    <div class=\"frame\">\n      <div class=\"hero-icon\">👨‍💻</div>\n      <h1 class=\"title\">컴퓨터 수업</h1>\n      <div class=\"subtitle-wrap\">\n        <p class=\"subtitle\">보고 따라하고, 손으로 직접 해보는 수업입니다</p>\n        <div class=\"subtitle-small\">Learn by watching and following</div>\n        <div class=\"subtitle-small\">Учимся, смотря и повторяя</div>\n      </div>\n\n      <div class=\"grid\">\n        <div class=\"card\">\n          <img src=\"https://images.unsplash.com/photo-1509062522246-3755977927d7?auto=format&fit=crop&w=1200&q=80\" alt=\"선생님이 설명하는 모습\" />\n          <div class=\"card-body\">\n            <p class=\"card-title\">설명</p>\n            <p class=\"card-text\">선생님이 화면을 보며 천천히 설명합니다</p>\n            <div class=\"card-trans\">Teacher explains step by step / Учитель объясняет шаг за шагом</div>\n          </div>\n        </div>\n\n        <div class=\"card\">\n          <img src=\"https://images.unsplash.com/photo-1516321497487-e288fb19713f?auto=format&fit=crop&w=1200&q=80\" alt=\"학생과 함께 실습하는 모습\" />\n          <div class=\"card-body\">\n            <p class=\"card-title\">연습</p>\n            <p class=\"card-text\">보고 따라하면서 같이 직접 연습합니다</p>\n            <div class=\"card-trans\">Practice together / Практикуем вместе</div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </section>\n</body>\n</html>\n"
